from pydantic import BaseModel, Field
from typing import Optional

class Invoice(BaseModel):
    invoice_number: str = Field(..., description="Unique invoice ID")
    date: str = Field(..., description="Invoice date in YYYY-MM-DD")
    total_amount: float = Field(..., ge=0)
    vendor_name: str = Field(..., min_length=2)
    line_items: list[dict] = Field(default_factory=list)

    class Config:
        json_schema_extra = {
            "example": {
                "invoice_number": "INV-12345",
                "date": "2024-01-15",
                "total_amount": 1250.75,
                "vendor_name": "Acme Corp"
            }
        }

import { z } from 'zod';

const InvoiceSchema = z.object({
  invoiceNumber: z.string().min(1, 'Invoice number required'),
  date: z.string().regex(/^\d{{4}}-\d{{2}}-\d{{2}}$/, 'Invalid date format'),
  totalAmount: z.number().positive(),
  vendorName: z.string().min(2),
  lineItems: z.array(z.object({
    description: z.string(),
    quantity: z.number().int().positive(),
    price: z.number().positive()
  })).optional()
});

type Invoice = z.infer<typeof InvoiceSchema>;

export { InvoiceSchema, Invoice };

import { Kernel, KernelArguments } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const extractInvoice = async (
  kernel: Kernel,
  context: KernelArguments
): Promise<string> => {
  const documentText = context.variables.document;
  const schema = InvoiceSchema.safeParse({}).success ? InvoiceSchema.schema : '';

  const prompt = `Extract invoice following this schema: ${JSON.stringify(schema)}\n\nDocument: ${documentText}\n\nReturn ONLY valid JSON:`;

  const chatService = kernel.addChatService(
    'gpt-4',
    new OpenAIChatCompletion('gpt-4')
  );

  const result = await kernel.invokePrompt(prompt, { serviceId: 'gpt-4' });
  return result.toString();
};

